INSERT INTO public.photos VALUES (24950, 'Avenida de los Bearneses 1971', 'Mesa del jurado, presidido por el concejal Alfonso Solâ”śĂ­ns Serrano, del "II Concurso nacional de elegancia automovilâ”śÂˇstica", organizado por la Escuela de Turismo de Zaragoza y patrocinado por Almacenes Gay. Este certamen, celebrado en mayo de 1971 durante las Fiestas de Primavera, tuvo una tercera ediciâ”śâ”‚n al aâ”śâ–’o siguiente, quedando suspendido en 1973 por motivo del fallecimiento de su principal organizador. En la imagen, el pâ”śâ•‘blico congregado en la grada colocada en la avenida de los Bearneses del parque de Primo de Rivera, celebra la presencia de un histriâ”śâ”‚nico grupo participante, al que no le falta el botijo. Mientras, los jurados beben cerveza, fuman y sonrâ”śÂˇen.', 1971, 1971, 1971, 'Anos 70', 'UNIVERSIDAD', 41.63390100, -0.89449500, '0101000020E6100000C8EF6DFAB39FECBF6BF3FFAA23D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33829068698.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33829068698.webp', 'https://www.flickr.com/photos/zaragozaantigua/33829068698/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26044, 'Cementos Portland 1955', 'Imagen en altura centrada en las instalaciones de Miraflores de la empresa "Cementos Portland Zaragoza, S.A.", que permite un interesante panorama del sureste de la ciudad. La captura se ha realizado desde la vertical de la carretera de Castellâ”śâ”‚n, y la enorme cementera aparece flanqueada por dos lâ”śÂˇneas ferroviarias: inmediata, la de Utrillas, con su correspondiente apeadero "Cementos"; hacia la izquierda, la lâ”śÂˇnea hacia Barcelona, con la estaciâ”śâ”‚n de Miraflores, y la recta zanja que se introduce despejada hasta el cruce con el camino de las Torres y la huerta de Miraflores. Un poco antes, pasa cerca de los pabellones de la Granja Agrâ”śÂˇcola, el Grupo Agustâ”śÂˇn Gericâ”śâ”‚, y el Grupo Puente Virrey-Rosellâ”śâ”‚n. A la derecha, la chimenea y la fâ”śĂ­brica de briquetas de MFU, entre los campos de la Granja. A la izquierda, el camino de Miraflores y sus alabeados aterrazamientos en descenso hasta las vâ”śÂˇas del tren, y al fondo, clarea la gran mole de la Residencia Josâ”śÂ® Antonio, como si de un zigurat mesopotâ”śĂ­mico se tratara. Fuente visual: Arxiu Nacional de Catalunya.', 1955, 1955, 1955, 'Anos 50', 'SAN JOSâ”śĂ«', 41.63145000, -0.86343500, '0101000020E6100000A818E76F42A1EBBF9487855AD3D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31595612412.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31595612412.webp', 'https://www.flickr.com/photos/zaragozaantigua/31595612412/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24000, 'Santiago Auserâ”śâ”‚n 1987', 'Foto: Rodolfo Alonso. El cantante, compositor y guitarrista Santiago Auserâ”śâ”‚n (Zaragoza, 1954), segundo por la izquierda, actuando entre los miembros del grupo Mâ”śĂ­s Birras Mauricio Aznar y Miguel Mata, en el bar Paradâ”śÂˇs de Zaragoza, durante las fiestas del Pilar de 1987. Este mâ”śâ•‘sico formâ”śâ”‚ parte del grupo Radio Futura y continuâ”śâ”‚ su carrera con el nombre de Juan Perro. En 2015 presentâ”śâ”‚ su tesis doctoral "Mâ”śâ•‘sica en los fundamentos del logos", sobre la mâ”śâ•‘sica y el pensamiento griego antiguo. Fuente visual: www.facebook.com/zgz80s/photos/a.127459403989874.22917.12...', 1987, 1987, 1987, 'Anos 80', 'SAN JOSâ”śĂ«', 41.64187300, -0.88434600, '0101000020E610000039268BFB8F4CECBFBB97FBE428D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21696092939.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21696092939.webp', 'https://www.flickr.com/photos/zaragozaantigua/21696092939/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24403, 'C.â”¬â•‘ de las Torres 1976', 'Imagen donde domina la achaflanada fachada del convento de nueva planta de la "Congregaciâ”śâ”‚n de las Hermanas Oblatas del Santâ”śÂˇsimo Redentor", construido en los aâ”śâ–’os 60 en la esquina de la plaza del doctor Albert Schweitzer con el camino de las Torres. A la derecha, la acequia de las Adulas del Huerva, y la chimenea de la fâ”śĂ­brica textil "Lanera Aragonesa". Fuente visual: Gerardo Sancho Ramo, AMZ.', 1976, 1976, 1976, 'Anos 70', 'SAN JOSâ”śĂ«', 41.64255700, -0.88212300, '0101000020E6100000C09481035A3AECBF6E68CA4E3FD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29545286474.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29545286474.webp', 'https://www.flickr.com/photos/zaragozaantigua/29545286474/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24424, 'PP. Agustinos y câ”śĂ­nidos c.1945', 'Curiosa imagen centrada en un recoleto espacio de la zona mâ”śĂ­s norteâ”śâ–’a del convento-colegio de los PP. Agustinos en el camino de las Torres, capturada desde donde estaba proyectado erigir la gran agustina iglesia, cosa que finalmente no se realizarâ”śÂˇa. El muro perimetral en ladrillo del convento-colegio aparece interrumpido bruscamente junto a una pequeâ”śâ–’a y feraz zona ajardinada que incluâ”śÂˇa una antigua "torre" que fue de Mercadal, con espadaâ”śâ–’a propia, y que quedâ”śâ”‚ incluida en el moderno recinto agustino, como muestra el padre agustino que posa entre dos perros guardianes. Junto a esta torre fluâ”śÂˇa un ramal derivado de la inmediata gran acequia de las Adulas, o de San Josâ”śÂ®, para riego de los cultivos de Miraflores. A la derecha sobresale la chimenea de la antigua fâ”śĂ­brica de hilados denominada "Lanera Aragonesa", en el cercano camino de las Torres. Al fondo, de enfre la foresta emerge perfilado el remate de la fachada del antiguo convento de las MM. Oblatas en el paseo de las Damas. Fuente visual: foto Juan Mora Insa, en Archivo Josâ”śÂ® Marâ”śÂˇa Ballestâ”śÂˇn Miguel.', 1945, 1945, 1945, 'Anos 40', 'SAN JOSâ”śĂ«', 41.64222100, -0.88124300, '0101000020E610000094861A852433ECBFF7E6374C34D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40316980895.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40316980895.webp', 'https://www.flickr.com/photos/zaragozaantigua/40316980895/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21161, 'Apeadero Miraflores 1894', 'Apeadero de Miraflores al poco de ser inaugurado en el mes de julio de ese aâ”śâ–’o, con posado de sus primeros habitantes. Esta infraestructura ferroviaria acortaba y agilizaba notablemente el trâ”śĂ­fico de trenes entre Madrid y Barcelona, y unos aâ”śâ–’os despuâ”śÂ®s permitirâ”śĂ­ tambiâ”śÂ®n el enlace con la lâ”śÂˇnea de Utrillas. Este original y pequeâ”śâ–’o edificio serâ”śĂ­ luego ampliado, y otros edificios e instalaciones surgirâ”śĂ­n en el lugar, conforme la lâ”śÂˇnea fuera desarrollando servicios. Fuente visual: AVV. San Josâ”śÂ®.', 1894, 1894, 1894, 'Siglo XIX', 'SAN JOSâ”śĂ«', 41.63220400, -0.86675000, '0101000020E610000023DBF97E6ABCEBBF4033880FECD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20355205536.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20355205536.webp', 'https://www.flickr.com/photos/zaragozaantigua/20355205536/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21331, 'Estaciâ”śâ”‚n de Utrillas 1908', 'En la estaciâ”śâ”‚n de Zaragoza de la sociedad Minas y Ferrocarril de Utrillas, antigua de Cappa, unos operarios posan junto a uno de los cinco coches de viajeros de 1â”¬Â¬ y 2â”¬Â¬ clase construidos en los talleres de Carde y Escoriaza, en servicio para viajeros en la lâ”śÂˇnea que habâ”śÂˇa sido (re) inaugurada en 1904. Al fondo y a la izquierda, el cocherâ”śâ”‚n donde estos coches eran guardados. Los edificios principales de la estaciâ”śâ”‚n quedaban justo a la derecha, fuera de plano. Hacia el fondo, muros que delimitaban la vecina huerta de Izuzquiza incrustada entre el camino de Cabaldâ”śâ”‚s (izquierda) y la calle de Miguel Servet (derecha) en el tramo entre las calles de la Mina, la Higuera, y Belchite.', 1908, 1908, 1908, 'Anos 1900', 'SAN JOSâ”śĂ«', 41.64081600, -0.86843400, '0101000020E6100000BB80971936CAEBBF7460394206D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50805924853.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50805924853.webp', 'https://www.flickr.com/photos/zaragozaantigua/50805924853/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21367, 'La Granja c.1910', 'Foto Antonio Arguas Perdiguer. Vista desde dentro de la puerta de entrada a la Granja Agrâ”śÂˇcola en el camino del Bajo Aragâ”śâ”‚n. Al fondo, "Villa Asunciâ”śâ”‚n" de Miguel Larrinaga, con su original apariencia diseâ”śâ–’ada por Fâ”śÂ®lix Navarro, que muriâ”śâ”‚ en 1911 y fue sustituido por el arquitecto Fernando de Escondrillas, que le dio su propio toque en el acabado final.', 1910, 1910, 1910, 'Anos 10', 'SAN JOSâ”śĂ«', 41.63810900, -0.86501200, '0101000020E6100000BFB854A52DAEEBBF4224438EADD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14994220090.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14994220090.webp', 'https://www.flickr.com/photos/zaragozaantigua/14994220090/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24953, 'Cabezo de Buenavista 1909', 'Imagen centrada parcialmente en la puerta de ingreso a la casa del guarda del Cabezo de Buenavista, donde una singular rondalla posa, junto a la guardesa e hijos, y un par de seâ”śâ–’oras con llamativas bufandas, durante una costumbrista visita a este lejano paraje de la ciudad que se convirtiâ”śâ”‚ con el tiempo en un antropolâ”śâ”‚gico reportaje fotogrâ”śĂ­fico. Al fondo y a la derecha, despejado entorno ascendente hacia el Cabezo, tradicionalmente despoblado de vegetaciâ”śâ”‚n hasta la transformaciâ”śâ”‚n acometida aâ”śâ–’os despuâ”śÂ®s durante la configuraciâ”śâ”‚n del parque de Buenavista.', 1909, 1909, 1909, 'Anos 1900', 'UNIVERSIDAD', 41.63287700, -0.89263900, '0101000020E6100000E84A04AA7F90ECBFFFB1101D02D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48528884276.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48528884276.webp', 'https://www.flickr.com/photos/zaragozaantigua/48528884276/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21387, 'Estaciâ”śâ”‚n de Utrillas 1917', 'La Europa continental sigue en guerra, y el crisol que la alimenta es abastecido hasta por el ferrocarril de Utrillas, que transporta carbâ”śâ”‚n, abonos minerales, cementos, madera, y otros materiales estratâ”śÂ®gicos hacia los paâ”śÂˇses en conflicto bâ”śÂ®lico, porque la guerra es, fundamentalmente, otra forma de hacer negocios. Por ello, el personal de la lâ”śÂˇnea aumenta en nâ”śâ•‘mero, y en la terminal de Zaragoza, ante la boca de entrada a uno de los depâ”śâ”‚sitos de locomotoras, posan en un antropolâ”śâ”‚gico retrato colectivo. La mayorâ”śÂˇa de ellos vivâ”śÂˇan en las inmediaciones de la Estaciâ”śâ”‚n. De estos monumentales Depâ”śâ”‚sitos de Locomotoras, sin mediar una guerra, sâ”śâ”‚lo quedaron en pie los arcos de entrada hasta mediados de los aâ”śâ–’os 90. Luego, fuese, y no hubo nada. En esta misma ubicaciâ”śâ”‚n hoy queda su etâ”śÂ®reo recuerdo en el "Parque de los Arcos", al lado de la trasplantada Chimenea de la Estaciâ”śâ”‚n. Este parque conserva la planta semicircular del Depâ”śâ”‚sito, y ya estâ”śĂ­. Fuente visual: www.flickr.com/photos/ferrocarril-utrillas/10799465686/in...', 1917, 1917, 1917, 'Anos 10', 'SAN JOSâ”śĂ«', 41.63922800, -0.86757100, '0101000020E610000011A8FE4124C3EBBF00581D39D2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19646874703.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19646874703.webp', 'https://www.flickr.com/photos/zaragozaantigua/19646874703/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21438, 'Ctra. de Castellâ”śâ”‚n c.1910', 'Imagen centrada en la novâ”śÂˇsima "Villa Asunciâ”śâ”‚n", o vivienda unifamiliar impulsada por el vizcaâ”śÂˇno Miguel Larrinaga y diseâ”śâ–’ada por el arquitecto Fâ”śÂ®lix Navarro Pâ”śÂ®rez con aires neorrenacentistas expresados en formas eclâ”śÂ®cticas y simbolistas. Esta gran casa fue construida en una parcela dentro de los extensos terrenos que este naviero poseâ”śÂˇa en la carretera de Zaragoza a Castellâ”śâ”‚n, confrontando desde la estaciâ”śâ”‚n de Cappa y hasta la Granja Agrâ”śÂˇcola, y con la direcciâ”śâ”‚n postal de Montemolâ”śÂˇn nâ”¬â•‘ 95. La original câ”śâ•‘pula central que remata en la imagen la caja de la escalera serâ”śÂˇa pocos aâ”śâ–’os despuâ”śÂ®s sustituida por un cimborrio de planta octogonal diseâ”śâ–’ado por el arquitecto Fernando de Escondrillas, La denominaciâ”śâ”‚n de esta villa respondâ”śÂˇa al nombre de Asunciâ”śâ”‚n Clavero, la turolense esposa de Larrinaga, cuya muerte en 1939 determinâ”śâ”‚ que esta casa nunca fuera ocupada por la familia Larrinaga-Clavero. Sin habitar durante muchos aâ”śâ–’os, durante la guerra civil de 1936-39 fue habilitada ocasionalmente como residencia militar por los nacionalistas. Al principio de los aâ”śâ–’os 40 la propiedad recayâ”śâ”‚ en las manos de la empresa Guiral Industrias Elâ”śÂ®ctricas SA (GIESA), que en 1942 se la vendiâ”śâ”‚ a la Compaâ”śâ–’â”śÂˇa de Marâ”śÂˇa, que pocos aâ”śâ–’os despuâ”śÂ®s abrieron aquâ”śÂˇ el marianista Colegio de Santa Marâ”śÂˇa del Pilar de Zaragoza, luego reconvertido en Casa de Formaciâ”śâ”‚n. Fuente visual: AMZ.', 1910, 1910, 1910, 'Anos 10', 'SAN JOSâ”śĂ«', 41.63841500, -0.86449700, '0101000020E6100000FFAECF9CF5A9EBBF4F232D95B7D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/44503596502.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/44503596502.webp', 'https://www.flickr.com/photos/zaragozaantigua/44503596502/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21464, 'Miguel Servet c.1912', 'Imagen de una de las jardineras en servicio en los tranvâ”śÂˇas de Zaragoza, estacionada en las vâ”śÂˇas de acceso al "cocherâ”śâ”‚n" de la empresa sito en la antigua carretera de Zaragoza a Castellâ”śâ”‚n o moderna calle de Miguel Servet. Tras el coche, edificio de la zona de talleres, oficinas y almacenes de la empresa. Estas unidades jardineras tenâ”śÂˇan un uso estacional, en funciâ”śâ”‚n del singular clima zaragozano, que en principio podrâ”śÂˇa abarcar desde la primavera hasta el otoâ”śâ–’o. Este carâ”śĂ­cter estacional fue lo que determinâ”śâ”‚ que aâ”śâ–’os mâ”śĂ­s tarde los vehâ”śÂˇculos jardinera (tanto los remolques como las motoras) fueran remodelados para hacerlos cerrados, â”śâ•‘tiles asâ”śÂˇ durante todo el aâ”śâ–’o.', 1912, 1912, 1912, 'Anos 10', 'SAN JOSâ”śĂ«', 41.63954900, -0.86676100, '0101000020E61000001D588E9081BCEBBF4298DBBDDCD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53453925922.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53453925922.webp', 'https://www.flickr.com/photos/zaragozaantigua/53453925922/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21542, 'Estaciâ”śâ”‚n de Utrillas c.1925', 'Posado de directivos y empeados en torno a la locomotora nâ”śâ•‘mero 51, bautizada "Baselga" en homenaje al local prâ”śâ”‚cer Mariano Baselga, fundador de la sociedad Minas y Ferrocarriles de Utrillas. Este pedazo de cacharro habâ”śÂˇa venido de Philadelphia (Estados Unidos de Norteamâ”śÂ®rica), y tenâ”śÂˇa como nombre de fâ”śĂ­brica "Mallet 030+030 T Baldwin 1917-45631". Podâ”śÂˇa remolcar composiciones (convoyes) de hasta 25 unidades. En el Depâ”śâ”‚sito de Locomotoras de la Terminal de Zaragoza de aquellos aâ”śâ–’os cabâ”śÂˇan 12 como â”śÂ®sta, o similares. Menudo espectâ”śĂ­culo sonoro. Todo esto sucedâ”śÂˇa muy cerca de donde hoy se puede escuchar el estacional crotoreo, o claqueteo, de los picos de las cigâ”śâ•ťeâ”śâ–’as de la trasplantada chimenea de la antigua Utrillas.', 1925, 1925, 1925, 'Anos 20', 'SAN JOSâ”śĂ«', 41.63922800, -0.86757100, '0101000020E610000011A8FE4124C3EBBF00581D39D2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20078055910.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20078055910.webp', 'https://www.flickr.com/photos/zaragozaantigua/20078055910/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21545, 'Fâ”śĂ­brica Briquetas Utrillas 1923', 'Imagen de la fâ”śĂ­brica de briquetas, o aglomerados de carbâ”śâ”‚n en forma de pastillas utilizadas como combustible de locomotoras, prâ”śâ”‚xima a la Estaciâ”śâ”‚n de Utrillas. La instalaciâ”śâ”‚n estâ”śĂ­ funcional, a plena actividad. Fuente visual: "Memoria de prâ”śĂ­cticas de 1923 del alumno Santiago Baselga, de la Escuela Especial de Minas de Madrid", Hemeroteca de la Escuela Tâ”śÂ®cnica Superior de Ingenieros de Minas de la Universidad Politâ”śÂ®cnica de Madrid.', 1923, 1923, 1923, 'Anos 20', 'SAN JOSâ”śĂ«', 41.63586000, -0.86688900, '0101000020E61000007C6308008EBDEBBFD36A48DC63D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20131353328.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20131353328.webp', 'https://www.flickr.com/photos/zaragozaantigua/20131353328/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21878, 'Calle de Miguel Servet 1936', 'Imagen de la "Villa Asunciâ”śâ”‚n" que fuera construida a principios de siglo para ser la definitiva casa de la pudiente familia Larrinaga-Clavero, residente en Liverpool por motivos empresariales. Diseâ”śâ–’ada por el arquitecto Fâ”śÂ®lix Navarro Pâ”śÂ®rez, tras su muerte y a requerimiento del propietario la casa fue modificada sustancialmente por el arquitecto Fernando de Escondrillas: por ejemplo, las torrecillas angulares fueron recrecidas en altura y redefinidas sus lâ”śÂˇneas y remate, y la original câ”śâ•‘pula central sobre la caja de la escalera fue sustituida por un cimborrio de planta octogonal. Este es el aspecto que presenta en esta fotografâ”śÂˇa. Tras el fallido golpe de Estado de julio de 1936 y el comienzo de la subsiguiente guerra civil, una iniciativa del alcalde Miguel Lâ”śâ”‚pez de Gera proyectâ”śâ”‚ establecer en esta gran casa una "escuela de reeducaciâ”śâ”‚n profesional para los mutilados de la guerra", si bien esta idea no cuajâ”śâ”‚. Durante la guerra esta casa fue militarizada al ser ocupada por el ejâ”śÂ®rcito nacionalista como residencia temporal de tropas fascistas italianas que transitaban por la ciudad, como sucediâ”śâ”‚ tambiâ”śÂ®n con otros destacados espacios y edificios de Zaragoza. En 1939 falleciâ”śâ”‚ Asunciâ”śâ”‚n Clavero, y Miguel Larrinaga ya no regresarâ”śÂˇa nunca a la ciudad. Por ello, poco despuâ”śÂ®s venderâ”śÂˇa la casa a la empresa GIESA, que estableciâ”śâ”‚ en esa zona su nueva y gran factorâ”śÂˇa. Fuente visual: "Aragâ”śâ”‚n: revista grâ”śĂ­fica de cultura aragonesa" (1936).', 1936, 1936, 1936, 'Anos 30', 'SAN JOSâ”śĂ«', 41.63841500, -0.86449700, '0101000020E6100000FFAECF9CF5A9EBBF4F232D95B7D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/44578007961.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/44578007961.webp', 'https://www.flickr.com/photos/zaragozaantigua/44578007961/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21927, 'Vista aâ”śÂ®rea (Este) c.1949', 'Finales aâ”śâ–’os 40 (s. XX). Posible aâ”śÂ®rea vista viniendo volando desde la Cartuja Baja, y observando un pedazo de la Zaragoza del momento. Mil y un detalles sobre los que hablar. Por ejemplo, en el extremo inferior izquierdo queda el quesito que forman Miguel Servet con la Av. San Josâ”śÂ®. Tras la aguja de las Hermanitas de los Pobres, los campos de Miraflores. En Miguel Servet, la enorme estructura del Macelo municipal sigue siendo extraordinaria. Enfrente, la calle Matadero. Y cerca, el Frontâ”śâ”‚n Zaragozano. El Camino rural que hoy es Compromiso de Caspe conduce a eso, a los campos de lo que poco despuâ”śÂ®s comenzarâ”śĂ­ a ser identificado como Las Fuentes. Junto al Huerva, insâ”śâ”‚lita visiâ”śâ”‚n del Cuartel de Intendencia que antes fue Penal, y que aâ”śâ•‘n antes fue Convento de S. Josâ”śÂ®. Al fondo, tras cruzar el Ebro, la Zaragoza del otro lado, bastante mâ”śĂ­s lejos de los montes de Juslibol que en la actualidad. Et cetera.', 1949, 1949, 1949, 'Anos 40', 'SAN JOSâ”śĂ«', 41.64201800, -0.86778000, '0101000020E6100000A2EE0390DAC4EBBFBFB854A52DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14860286855.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14860286855.webp', 'https://www.flickr.com/photos/zaragozaantigua/14860286855/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21944, 'Colegio Marianistas 1946', 'El 7 de octubre de 1946 comenzâ”śâ”‚ el primer curso del Colegio de Santa Marâ”śÂˇa del Pilar (Marianistas) en el palacio de Larrinaga, anterior propiedad de GIESA, que se las vendiâ”śâ”‚ por 2.195.000 de pesetas a pagar en cinco aâ”śâ–’os. Los muebles y enseres fueron trasladados desde la anterior residencia de estos religiosos, sito en la calle de San Pablo. En la imagen, capturada en la zona trasera del palacio, con las nuevas instalaciones fabriles de GIESA asomando por la derecha, posado del original equipo de docentes, encabezado por el director Esteban Ichaso: Jesâ”śâ•‘s Arcauz, Eugenio salazar, Josâ”śÂ® Marâ”śÂˇa Santamarâ”śÂˇa y Josâ”śÂ® Antonio Fernâ”śĂ­ndez; el capellâ”śĂ­n, Fâ”śÂ®lix Fernâ”śĂ­ndez; y 8 de los 17 alumnos inscritos, presentes a la hora de tomarla fotografâ”śÂˇa.', 1946, 1946, 1946, 'Anos 40', 'SAN JOSâ”śĂ«', 41.63834300, -0.86441300, '0101000020E61000008997A77345A9EBBFB5503239B5D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15740889556.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15740889556.webp', 'https://www.flickr.com/photos/zaragozaantigua/15740889556/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22014, 'Calle de Miguel Servet c.1946', 'Imagen de Villa Asunciâ”śâ”‚n que fuera construida a principios de siglo para la pudiente familia Larrinaga-Clavero. Diseâ”śâ–’ada originalmente por el arquitecto Fâ”śÂ®lix Navarro, tras su muerte y a requerimiento del propietario la casa fue modificada sustancialmente por el arquitecto Fernando de Escondrillas. Tras el fallido golpe de Estado de julio de 1936 y el comienzo de la subsiguiente guerra civil, el alcalde Miguel Lâ”śâ”‚pez de Gera proyectâ”śâ”‚ establecer aquâ”śÂˇ una "escuela de reeducaciâ”śâ”‚n profesional para los mutilados de la guerra", que no cuajâ”śâ”‚. Durante la guerra la casa fue militarizada por el ejâ”śÂ®rcito nacionalista para dar cabida a altos mandos en su temporal paso por la ciudad, incluyendo fascistas italianos. En 1939 falleciâ”śâ”‚ Asunciâ”śâ”‚n Clavero, y en 1942 Miguel Larrinaga vendiâ”śâ”‚ la casa a la empresa GIESA, que la habilitâ”śâ”‚ como dependencias administrativas y oficinas. En 1946, fue nuevamente vendida, en esta ocasiâ”śâ”‚n a los Padres Marianistas para ubicar en sus dependencias el colegio Santa Marâ”śÂˇa del Pilar. En la imagen, vista de la fachada e ingreso principal a la casa desde la calle de Miguel Servet, en un entorno bien despejado y luminoso.', 1946, 1946, 1946, 'Anos 40', 'SAN JOSâ”śĂ«', 41.63831400, -0.86451800, '0101000020E6100000DDB419A721AAEBBF1B4AED45B4D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48430429356.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48430429356.webp', 'https://www.flickr.com/photos/zaragozaantigua/48430429356/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22022, 'Casa de Larrinaga c.1942', 'Imagen capturada en la parte trasera de Villa Asunciâ”śâ”‚n o casa de Miguel Larrinaga, con una incursiâ”śâ”‚n visual, a la derecha, de las obras de construcciâ”śâ”‚n de la nueva fâ”śĂ­brica de Guiral Industrias Elâ”śÂ®ctricas S.A., cuya conclusiâ”śâ”‚n se prolongâ”śâ”‚ hasta 1945. Entre la casa y las obras, al fondo y al otro lado de la calle de Miguel Servet, las cocheras de los tranvâ”śÂˇas. En primer tâ”śÂ®rmino, la sombra del retratador y su artefacto, parcialmente retratados.', 1942, 1942, 1942, 'Anos 40', 'SAN JOSâ”śĂ«', 41.63861100, -0.86396000, '0101000020E61000004BAB21718FA5EBBFD4EE5701BED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50018662068.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50018662068.webp', 'https://www.flickr.com/photos/zaragozaantigua/50018662068/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22093, 'Estaciâ”śâ”‚n de Utrillas c.1959', 'Estaciâ”śâ”‚n terminal de Zaragoza de la compaâ”śâ–’â”śÂˇa Minas y Ferrocarriles de Utrillas. Vista desde el andâ”śÂ®n principal, el mar de vâ”śÂˇas, sus almacenes y edificios auxiliares. Aâ”śâ–’os despuâ”śÂ®s, tras su clausura como lâ”śÂˇnea todo este patrimonio ferroviario rodante serâ”śĂ­ vendido a precio de chatarra, o directamente desguazado, y la estaciâ”śâ”‚n quedarâ”śĂ­ varada en el tiempo por un cuarto de siglo, y luego urbanizada para otros usos. Es muy de nuestra ciudad que en cualquier memoria de la historia ferroviaria espaâ”śâ–’ola y europea aparezcan decenas de referencias a locomotoras que dieron servicio en la humilde lâ”śÂˇnea Utrillas-Zaragoza, y que no quede ni rastro de ellas en el lugar que fue terminal y estaciâ”śâ”‚n mâ”śĂ­s grande de la lâ”śÂˇnea. Ni siquiera ha habido ocurrencias del tipo "parque temâ”śĂ­tico del tren". Nada. Cero. Al fondo, en el centro de la imagen, y sobre la lâ”śÂˇnea del horizonte, sobresale la aguja del Hogar San Josâ”śÂ® de las HH. de los Ancianos Desamparados. Fuente visual: Foto Christian Schnabel.', 1959, 1959, 1959, 'Anos 50', 'SAN JOSâ”śĂ«', 41.63995000, -0.86791900, '0101000020E6100000FB761211FEC5EBBFA089B0E1E9D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19694146654.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19694146654.webp', 'https://www.flickr.com/photos/zaragozaantigua/19694146654/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22096, 'Estaciâ”śâ”‚n de Miraflores c.1959', 'Imagen de la estaciâ”śâ”‚n de Miraflores en sus activos aâ”śâ–’os como empalme con la lâ”śÂˇnea Madrid-Barcelona para los trenes carboneros de la lâ”śÂˇnea Utrillas-Zaragoza. Fuente visual: AVV. San Josâ”śÂ®.', 1959, 1959, 1959, 'Anos 50', 'SAN JOSâ”śĂ«', 41.63220400, -0.86675000, '0101000020E610000023DBF97E6ABCEBBF4033880FECD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20134934869.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20134934869.webp', 'https://www.flickr.com/photos/zaragozaantigua/20134934869/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22097, 'Estaciâ”śâ”‚n de Utrillas c.1959', 'Estaciâ”śâ”‚n terminal de Zaragoza de la compaâ”śâ–’â”śÂˇa Minas y Ferrocarriles de Utrillas. En el centro, el edificio principal de la estaciâ”śâ”‚n. A la izquierda, acceso al mar de vâ”śÂˇas y a los depâ”śâ”‚sitos donde se guardaban las locomotoras. Fuente visual: Foto Christian Schnabel.', 1959, 1959, 1959, 'Anos 50', 'SAN JOSâ”śĂ«', 41.63995000, -0.86791900, '0101000020E6100000FB761211FEC5EBBFA089B0E1E9D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20318902021.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20318902021.webp', 'https://www.flickr.com/photos/zaragozaantigua/20318902021/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22108, 'Torre Ramona 1958', '"Torre Ramona. Parcelas del Catastro de Râ”śâ•‘stica del Tâ”śÂ®rmino Municipal de Zaragoza", abril de 1958. Plano de la zona conocida como Torre Ramona, en la barriada de Las Fuentes. Abajo, la Facultad de Veterinaria.', 1958, 1958, 1958, 'Anos 50', 'SAN JOSâ”śĂ«', 41.64198500, -0.86553900, '0101000020E61000008F334DD87EB2EBBFE3C281902CD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21457276382.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21457276382.webp', 'https://www.flickr.com/photos/zaragozaantigua/21457276382/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23371, 'Almenara de La Sagrada 1929', 'Imagen de la almenara de riego de Nuestra Seâ”śâ–’ora de La Sagrada en el Canal Imperial de Aragâ”śâ”‚n a su paso por Garrapinillos. Fuente visual: revista de la Confederaciâ”śâ”‚n Sindical Hidrogrâ”śĂ­fica del Ebro.', 1929, 1929, 1929, 'Anos 20', NULL, 41.67502600, -1.03376700, '0101000020E6100000CCF10A444F8AF0BF90F9804067D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19527238324.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19527238324.webp', 'https://www.flickr.com/photos/zaragozaantigua/19527238324/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22156, 'Calle Miguel Servet 1954', 'Vista aâ”śÂ®rea de la calle de Miguel Servet (arriba a la izquierda) y su entorno. Al fondo a la izquierda, la plaza de ingreso a la estaciâ”śâ”‚n de ferrocarril de Utrillas. A la derecha, el reformatorio del Buen Pastor en Torre Ramona. Junto al palacio de Larrinaga, la factorâ”śÂˇa GIESA. En primer plano, construcciâ”śâ”‚n de la nueva fâ”śĂ­brica CEFA. Fuente visual: Arxiu Nacional de Catalunya.', 1954, 1954, 1954, 'Anos 50', 'SAN JOSâ”śĂ«', 41.63954500, -0.86504600, '0101000020E6100000C423F1F274AEEBBF00A94D9CDCD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30291244463.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30291244463.webp', 'https://www.flickr.com/photos/zaragozaantigua/30291244463/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22158, 'Calle de Guiral 1958', 'Imagen del trolebâ”śâ•‘s nâ”¬â•‘ 39, construido en Zaragoza para dar servicio a la lâ”śÂˇnea del Barrio de Jesâ”śâ•‘s. La captura se ha realizado en la calle de Joaquâ”śÂˇn Guiral, al poco de salir de las cocheras de los trolebuses, que quedan a la izquierda, fuera de plano. Al fondo, la fachada principal de la fâ”śĂ­brica GIESA. Fuente visual: TUZSA.', 1958, 1958, 1958, 'Anos 50', 'SAN JOSâ”śĂ«', 41.63948300, -0.86508800, '0101000020E61000007F2F8507CDAEEBBF8AAC3594DAD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30499112050.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30499112050.webp', 'https://www.flickr.com/photos/zaragozaantigua/30499112050/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22162, 'Calle Miguel Servet 1954', 'Vista aâ”śÂ®rea de la calle de Miguel Servet, con la huerta de Las Fuentes al fondo. En el centro, la factorâ”śÂˇa GIESA. A su derecha, vista parcial del palacio de Larrinaga. Abajo a la izquierda, las cocheras de los Tranvâ”śÂˇas de Zaragoza. A la derecha, las carboneras de la estaciâ”śâ”‚n de ferrocarril de Utrillas, cuyas vâ”śÂˇas se ven abajo. Fuente visual: Arxiu Nacional de Catalunya.', 1954, 1954, 1954, 'Anos 50', 'SAN JOSâ”śĂ«', 41.63948300, -0.86508800, '0101000020E61000007F2F8507CDAEEBBF8AAC3594DAD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30730817080.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30730817080.webp', 'https://www.flickr.com/photos/zaragozaantigua/30730817080/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22184, 'Miguel Servet 1953', 'Imagen capturada sobrevolando el entorno de la calle Miguel Servet con vistas de las instalaciones de Guiral Industrias Elâ”śÂ®ctricas S.A. (GIESA), aâ”śâ•‘n sin su referencial atalaya en el extremo noroccidental del largo pabellâ”śâ”‚n de su fachada principal. A su derecha, tampoco figura la Harinera de Azâ”śâ”‚n. Al fondo, el edificio del Reformatorio del Buen Pastor. Al otro lado de Miguel Servet, el depâ”śâ”‚sito de carbâ”śâ”‚n de la estaciâ”śâ”‚n de ferrocarril de Utrillas aâ”śâ•‘n no ha sido ampliado con nuevos reservorios. A su izquierda, el perâ”śÂˇmetro averjado anuncia el ingreso principal a la antigua Granja Agrâ”śÂˇcola, ya despojada de sus funciones experimentales; tal vez por eso la puerta estâ”śĂ­ abierta. Por la portaza principal de GIESA, un camino de hierro comunicaba por ferrocarril con la estaciâ”śâ”‚n de Utrillas para dar salida a las mercaderâ”śÂˇas producidas. Una unidad tranviaria de la lâ”śÂˇnea "Bajo Aragâ”śâ”‚n" se encamina hacia la plaza de San Miguel, junto al hotelito de Larrinaga reconvertido en Colegio de Santa Marâ”śÂˇa del Pilar de los marianistas, pendiente de construir los traseros pabellones, y el cerrado que lo salvaguarde de ingresos no deseados. Fuente visual: Arxiu Nacional de Catalunya', 1953, 1953, 1953, 'Anos 50', 'SAN JOSâ”śĂ«', 41.63915200, -0.86484900, '0101000020E6100000444E5FCFD7ACEBBF259694BBCFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32003698102.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32003698102.webp', 'https://www.flickr.com/photos/zaragozaantigua/32003698102/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22340, 'Estaciâ”śâ”‚n de Utrillas 1965', 'Imagen capturada un aâ”śâ–’o antes del cierre decretado de la lâ”śÂˇnea de Zaragoza a Utrillas. La capacidad del Depâ”śâ”‚sito de locomotoras de la Estaciâ”śâ”‚n de Zaragoza, de las 12 unidades del principio, fue ampliada hasta las 16 de la imagen, junto a la placa giratoria del Depâ”śâ”‚sito. La locomotora nâ”¬â•‘ 207, descansando al lado de los operarios, a la derecha, fue la que protagonizâ”śâ”‚ el viaje de clausura de la lâ”śÂˇnea. A las 8 de la maâ”śâ–’ana del sâ”śĂ­bado dâ”śÂˇa 15 de enero de 1966 el jefe de la estaciâ”śâ”‚n de Utrillas-Montalbâ”śĂ­n dio la salida oficial a la â”śâ•‘ltima composiciâ”śâ”‚n, mixta con vagones cargados de carbâ”śâ”‚n, coche de viajeros, furgones y otros carruajes. Posteriormente, circulâ”śâ”‚ la locomotora nâ”¬â•‘ 7 (en primer plano), con furgâ”śâ”‚n y plataformas, para ultimar facturaciones que todavâ”śÂˇa llegaban desde Miraflores para los pueblos de la lâ”śÂˇnea, y para ir retirando materiales de las estaciones de la lâ”śÂˇnea. El 31 de marzo de 1966 FEVE (Ferrocarriles Espaâ”śâ–’oles de Vâ”śÂˇa Estrecha) colgâ”śâ”‚ el cartel del cierre total. Fuente visual: www.flickr.com/photos/ferrocarril-utrillas/9305907744/in/...', 1965, 1965, 1965, 'Anos 60', 'SAN JOSâ”śĂ«', 41.63922800, -0.86757100, '0101000020E610000011A8FE4124C3EBBF00581D39D2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20077268210.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20077268210.webp', 'https://www.flickr.com/photos/zaragozaantigua/20077268210/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22539, 'Miguel Servet 1972', 'Vehâ”śÂˇculo-grâ”śâ•‘a para asistencia a unidades de Tranvâ”śÂˇa averiadas, en el entorno de las cocheras ubicadas en Miguel Servet. La inequâ”śÂˇvoca presencia del Palacio de Larrinaga, al fondo, nos sitâ”śâ•‘a perfectamente. En la actualidad esta zona es una gran calle peatonal entre las calles Bubierca y Principado de Morea, la Plaza Sanz Briz y Miguel Servet. Fuente visual: www.flickr.com/photos/jhm0284/5813100892/in/photostream/', 1972, 1972, 1972, 'Anos 70', 'SAN JOSâ”śĂ«', 41.63794500, -0.86537700, '0101000020E61000002BBD361B2BB1EBBFC8D2872EA8D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14892217061.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14892217061.webp', 'https://www.flickr.com/photos/zaragozaantigua/14892217061/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22625, 'Camino de Cabaldâ”śâ”‚s 1971', 'Imagen tomada desde altura en el Camino de Cabaldâ”śâ”‚s del notable impacto de la nueva urbanizaciâ”śâ”‚n que la "Inmobiliaria Râ”śÂˇo Ebro" habâ”śÂˇa promovido al final de la calle Castelar. A la izquierda, aspecto de las abandonadas instalaciones de la estaciâ”śâ”‚n de Utrillas, con una interesante visual del semicircular depâ”śâ”‚sito de locomotoras aâ”śâ•‘n con el tejado casi intacto. Hacia la derecha, el Camino de Cabaldâ”śâ”‚s parece terminar, pero sâ”śâ”‚lo se convierte en una pista que se aventura entre campos de cultivo de herbâ”śĂ­ceas. Fuente visual: AMZ, Gerardo Sancho Ramo.', 1971, 1971, 1971, 'Anos 70', 'SAN JOSâ”śĂ«', 41.63978100, -0.86881000, '0101000020E610000021020EA14ACDEBBF14CD0358E4D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19921982094.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19921982094.webp', 'https://www.flickr.com/photos/zaragozaantigua/19921982094/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24954, 'Parque Grande 1976', 'Curiosa postal publicitaria de Residencial "Parque Ciudad", la gran manzana de nuevos bloques de viviendas construidas donde estuviera el gran complejo de la Editorial Luis Vives, entre el paseo de Fernando el Catâ”śâ”‚lico nâ”¬â•‘ 59-71 y la calle de Luis Vives (la nueva calle abierta ante el râ”śÂˇo todavâ”śÂˇa no tenâ”śÂˇa nombre). Se trata de una tâ”śÂˇpica vista del parque tomada desde la altura del Cabezo de Buenavista, a los pies del Monumento al Rey Alfonso I el Batallador, a la que se le ha impostado un dibujo de la nueva residencial de forma un poco gruesa, tanto por altura como por anchura, pues eclipsa a los bloques del â”śâ•‘ltimo tramo de los pares del paseo. Para remarcar la ubicaciâ”śâ”‚n, una indicativa mano "pop" seâ”śâ–’ala el objeto de promociâ”śâ”‚n.', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.63456900, -0.89453800, '0101000020E61000009AEFE0270EA0ECBF1807978E39D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50803178642.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50803178642.webp', 'https://www.flickr.com/photos/zaragozaantigua/50803178642/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22626, 'Camino de Cabaldâ”śâ”‚s 1975', 'Un Seat 124 y una moto no-GP transitan por un terroso Camino de Cabaldâ”śâ”‚s, mientras un raso rebaâ”śâ–’o se abastece de agua y ramonea en terrenos de la antigua Granja Agrâ”śÂˇcola Experimental, abandonada desde 1943. El pastor y un vecino, como Tip y Coll, hablando del Gobierno. A la derecha, un campo panizo. Al fondo, los bloques de edificios del final de la calle Cartagena, y los mâ”śĂ­s recientes del final de la calle Castelar. A la derecha, las traseras de la antigua estaciâ”śâ”‚n de ferrocarril de Utrillas, algunos bloques de Miguel Servet, las cocheras de los tranvâ”śÂˇas, ya muy menguadas de efectivos (justo un aâ”śâ–’o despuâ”śÂ®s serâ”śÂˇa piqueteada la â”śâ•‘ltima lâ”śÂˇnea en activo, la 11 "Parque-San Josâ”śÂ®") , y la torre de la fâ”śĂ­brica GIESA- Schindler. Hoy, donde los abrevaderos, estâ”śĂ­ la esquina del Parque de la Granja con Josâ”śÂ® Galiay; a la derecha queda el CDM La Granja; el Camino Cabaldâ”śâ”‚s estâ”śĂ­ asfaltado, y hasta pasa un bus; y la Prolongaciâ”śâ”‚n de Cesâ”śĂ­reo Alierta, que cruza de derecha a izquierda, ha hecho que esa zona sea muy transitada por trâ”śĂ­fico rodado, y cuando hay baloncesto, incluso parece el Paseo de la Independencia durante la segunda semana de octubre. Cuando la imagen, esto estaba a diez minutos del "centro", aunque la sensaciâ”śâ”‚n era como de aâ”śâ–’os luz, y ademâ”śĂ­s de los bisiestos. Fuente visual: AMZ, Gerardo Sancho Ramo.', 1975, 1975, 1975, 'Anos 70', 'SAN JOSâ”śĂ«', 41.63736800, -0.86907800, '0101000020E6100000F08975AA7CCFEBBF2BC24D4695D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20051716740.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20051716740.webp', 'https://www.flickr.com/photos/zaragozaantigua/20051716740/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22630, 'Trolebâ”śâ•‘s 1972', 'Imagen del trolebâ”śâ•‘s nâ”¬â•‘ 53 en el acceso a las cocheras de los tranvâ”śÂˇas de la ciudad en Miguel Servet. Adquiridos de segunda mano y con procedencia londinense, estos vehâ”śÂˇculos se incorporaron a las tres lâ”śÂˇneas de trolebâ”śâ•‘s urbano (Terminillo/Delicias en 1949, Gâ”śĂ­llego en 1954, Barrio de Jesâ”śâ•‘s en 1955). Nacida de forma peculiar como respuesta a los embates comerciales del sector privado, esta innovadora forma de transporte, mucho mâ”śĂ­s "flexible" que el "râ”śÂˇgido" tranvâ”śÂˇa, apenas llegâ”śâ”‚ a su edad madura: en octubre de 1974 fueron desmantelados, fueran o fuesen râ”śÂˇgidos, flexibles, o ambas cosas a la vez. En esta ciudad, el transporte pâ”śâ•‘blico que no fuese puro vehâ”śÂˇculo con motor a explosiâ”śâ”‚n, tenâ”śÂˇa las horas contadas. Fuente visual: www.flickr.com/photos/jhm0284/5813101264/in/album-7215763...', 1972, 1972, 1972, 'Anos 70', 'SAN JOSâ”śĂ«', 41.63794500, -0.86537700, '0101000020E61000002BBD361B2BB1EBBFC8D2872EA8D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20177613248.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20177613248.webp', 'https://www.flickr.com/photos/zaragozaantigua/20177613248/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22633, 'Ferrocarril de Utrillas 1975', 'Nueve aâ”śâ–’os despuâ”śÂ®s del desmantelamiento de la lâ”śÂˇnea minera de Utrillas a Zaragoza, este era el panorama donde la antigua lâ”śÂˇnea se bifurcaba en la fâ”śĂ­brica de briquetas MFU (Minas y Ferrocarriles de Utrillas). Hacia la derecha, las vâ”śÂˇas conducâ”śÂˇan a la Estaciâ”śâ”‚n de Miraflores, cuyo edificio de viviendas en blanco es parcialmente visible, y a los muelles de la fâ”śĂ­brica de cementos Portland. Hacia la izquierda, por donde los trenes iban-venâ”śÂˇan de las cuencas de lignitos de Teruel. En el centro, los restos fosilizados de la fâ”śĂ­brica de briquetas o aglomerados, con las "piscinas" o depâ”śâ”‚sitos de carbâ”śâ”‚n en primer plano, y luego el complejo de la fâ”śĂ­brica, el muelle de descarga, y la representativa chimenea que, a diferencia de su vecina gemela de la Estaciâ”śâ”‚n de Utrillas, fue piqueteada con el resto de la instalaciâ”śâ”‚n. Al fondo, la mole de la antigua fâ”śĂ­brica de cementos Portland, un patrimonio, en este caso industrial, que fue dinamitado para habilitar el solar donde las Ferias de octubre primero, ahora aparcadero de coches al otro lado del Tercer Cinturâ”śâ”‚n. En la actualidad, a la derecha se abre la calle Ducado de Atenas que conduce a la Estaciâ”śâ”‚n de Cercanâ”śÂˇas de Miraflores; a la izquierda el prolongado Cesâ”śĂ­reo Alierta lleva a la carretera de Castellâ”śâ”‚n; en el centro se levanta el municipal pabellâ”śâ”‚n de deportes donde juega el Club Baloncesto Zaragoza; y al fondo, el Tercer Cinturâ”śâ”‚n de Ronda. Fuente visual: AMZ, Gerardo Sancho Ramo.', 1975, 1975, 1975, 'Anos 70', 'SAN JOSâ”śĂ«', 41.63674200, -0.86723300, '0101000020E61000000B62A06B5FC0EBBFACFE08C380D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20231133642.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20231133642.webp', 'https://www.flickr.com/photos/zaragozaantigua/20231133642/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22639, 'Vista San Josâ”śÂ® 1975', 'Imagen capturada desde las alturas de un edificio del Camino de Cabaldâ”śâ”‚s, que ofrece una panorâ”śĂ­mica irrepetible de la desmantelada lâ”śÂˇnea ferroviaria Utrillas-Zaragoza, y el empalme de Miraflores. Los restos de la carbonilla permiten identificar lo que ya no es sino dos oscuros caminos en "y" que contrastan con la claridad de los otros senderos. En la conexiâ”śâ”‚n de las dos rutas, restos de la fâ”śĂ­brica de briquetas MFU con los vacâ”śÂˇos depâ”śâ”‚sitos de carbâ”śâ”‚n a modo de piscinas. Los verdes campos formaban parte de los terrenos de la antigua Granja Experimental. A la derecha, edificios de la Estaciâ”śâ”‚n de Miraflores, y altas higueras junto a la acequia del Camino del Junco. A la izquierda, la empresa Viguetas PITAY, S.A., materiales de construcciâ”śâ”‚n. Un poco mâ”śĂ­s al fondo, el monumental conjunto de la fâ”śĂ­brica de cemento Portland-Miraflores, y su extensa colecciâ”śâ”‚n de chimeneas. Fuente visual: Foto Hermâ”śâ”‚genes Pardo, AVV. San Josâ”śÂ®.', 1975, 1975, 1975, 'Anos 70', 'SAN JOSâ”śĂ«', 41.63674200, -0.86723300, '0101000020E61000000B62A06B5FC0EBBFACFE08C380D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20355998456.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20355998456.webp', 'https://www.flickr.com/photos/zaragozaantigua/20355998456/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22642, 'Estaciâ”śâ”‚n de Utrillas 1979', 'Decembrina y nevada imagen en altura del entorno de la antigua estaciâ”śâ”‚n de Utrillas. Inmediatas, las antiguas cocheras de los tranvâ”śÂˇas habilitadas como primeras cocheras de los autobuses urbanos. A su derecha, exoesqueleto de la estaciâ”śâ”‚n y traseras de los bloques de la calle Castelar. Al fondo, entre brumas, la abandonada fâ”śĂ­brica de briquetas de MFU y campos de La Granja. La fresca neblina no deja ver mâ”śĂ­s. La imagen estâ”śĂ­ capturada desde el bloque de viviendas con entrada por la plaza de Utrillas, construido sobre uno de los antiguos edificios para vivienda de trabajadores de la estaciâ”śâ”‚n de Cappa-Utrillas. Fuente visual: www.facebook.com/photo.php?fbid=10203363958714839&set...', 1979, 1979, 1979, 'Anos 70', 'SAN JOSâ”śĂ«', 41.63922800, -0.86757100, '0101000020E610000011A8FE4124C3EBBF00581D39D2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20489827995.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20489827995.webp', 'https://www.flickr.com/photos/zaragozaantigua/20489827995/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22883, 'Estaciâ”śâ”‚n de Utrillas 1985', 'La Estaciâ”śâ”‚n de Cappa-Utrillas comenzâ”śâ”‚ a ser construida en 1863, y los tres edificios que conformaban la entrada desde el Camino del Bajo Aragâ”śâ”‚n (Miguel Servet) fueron terminados en 1865. El central y mâ”śĂ­s ornado de ellos tenâ”śÂˇa un luminoso letrero en forja y cristal que, un poco disonante con el estilo sobrio y academicista del conjunto, indicaba la salida de la estaciâ”śâ”‚n al pasaje que llegaba del sureste de la provincia de Zaragoza y el noreste de Teruel. El desmantelamiento de la lâ”śÂˇnea en 1966 y su venta a una inmobiliaria iniciâ”śâ”‚ una degradante etapa hasta que en 1986 el edificio fue catalogado. Luego vino lo que vino. La imagen recuerda la existencia de este letrero que ni la catalogaciâ”śâ”‚n, ni la mâ”śĂ­s posterior restauraciâ”śâ”‚n, preservaron. Hoy estarâ”śÂˇa dando un poco de alegrâ”śÂˇa al frâ”śÂˇo, seco (por mâ”śĂ­s que llueva) y duro callejâ”śâ”‚n de losas y cemento en que han convertido el andâ”śÂ®n principal de la antigua Estaciâ”śâ”‚n.', 1985, 1985, 1985, 'Anos 80', 'SAN JOSâ”śĂ«', 41.64036700, -0.86774800, '0101000020E6100000CA6B257497C4EBBF0438BD8BF7D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19673543923.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19673543923.webp', 'https://www.flickr.com/photos/zaragozaantigua/19673543923/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22887, 'Estaciâ”śâ”‚n de Utrillas 1985', '1985. Las Mentes Sencillas y su "Don''t You (Forget About Me)" saturaban los diales comerciales de Radio, mientras la Estaciâ”śâ”‚n de Utrillas caminaba hacia su aniversario 20 de olvido promovido. En la imagen, captura desde uno de los dos hormigonados muelles del Depâ”śâ”‚sito de Locomotoras. Tras el levantamiento de vâ”śÂˇas, la naturaleza estepâ”śĂ­rea va reapropiâ”śĂ­ndose de lo que era suyo, mientras los 16 arcos de los 16 Depâ”śâ”‚sitos mantienen el tipo, aun sin cobertura protectora. Al fondo, de izquierda a derecha, el telâ”śâ”‚n de fondo de los bloques de Castelar y Camino Cabaldâ”śâ”‚s. El primero, el gran bloque del 81-91 de Castelar/37-39 de Camino Cabaldâ”śâ”‚s. Luego, el 72 del Camino Cabaldâ”śâ”‚s, esquina con Martâ”śÂˇn Abanto. Despuâ”śÂ®s, el pequeâ”śâ–’ito 72. Le sigue el 68-70, con el Cafâ”śÂ®-Bar "Mikado" en los bajos de su chaflâ”śĂ­n. Despuâ”śÂ®s, el 62-64, esquina con Luis Braille. Por detrâ”śĂ­s vemos asomar la gigantez del 54-56 de Privilegio de la Uniâ”śâ”‚n/15 de Luis Braille. Llegamos al 60 de Camino Cabaldâ”śâ”‚s y sus 10 alturas, justo donde emerge la chimenea MFU de la Estaciâ”śâ”‚n. Finalmente, el 58 de Privilegio de la Uniâ”śâ”‚n. Las enormes diferencias entre alturas ilustran câ”śâ”‚mo se juega al Monopoly en esta ciudad. Si esto era asâ”śÂˇ en un humilde barrio de la periferia, câ”śâ”‚mo no habrâ”śĂ­ sido en el "centro". Los terrenos de la antigua Estaciâ”śâ”‚n no serâ”śĂ­n ajenos al juego, ni mucho menos. Fuente visual: AVV San Josâ”śÂ®.', 1985, 1985, 1985, 'Anos 80', 'SAN JOSâ”śĂ«', 41.63922800, -0.86757100, '0101000020E610000011A8FE4124C3EBBF00581D39D2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20075589438.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20075589438.webp', 'https://www.flickr.com/photos/zaragozaantigua/20075589438/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22889, 'Estaciâ”śâ”‚n de Utrillas 1985', 'Del 23 al 25 de marzo de 1984 tuvo lugar la "I Muestra de Pop-Rock y otros rollos de Zaragoza" en el Pabellâ”śâ”‚n Francâ”śÂ®s de la Feria de Muestras. Patrocinado por Ayuntamiento, DPZ y DGA, pasaron por â”śÂ®l 52 grupos de la ciudad, entre ellos Ferrobâ”śâ”‚s, Zumo de Vidrio, Golden Zippers, Doctor Simâ”śâ”‚n y los Enfermos Mentales, Boda de Rubias, Pedro Botero... y una banda punk-rock denominada "Parkinson". El 21 de junio de 1985, en el Cine Venecia, este mismo grupo tocâ”śâ”‚ junto a IV Reich, Mas Birras, y Gastos Aparte, en el "Concierto desde el III Mundo por el hambre en Nueva York" (â”¬Â˝We Are the Worldâ”¬â•— local y somarda), cuya crâ”śâ”‚nica de Mariano Gistaâ”śÂˇn publicada en el periâ”śâ”‚dico "El Dâ”śÂˇa" un par de dâ”śÂˇas despuâ”śÂ®s, refleja câ”śâ”‚mo de loco estaba el movido medio ambiente zaragozano de aquellos elâ”śÂ®ctricos aâ”śâ–’os ochenta. Igualico al de ahora. En la imagen, un antisistâ”śÂ®mico posado fotogrâ”śĂ­fico del grupo Parkinson cerca de los arcos de entrada de los abandonados Depâ”śâ”‚sitos de Locomotoras de la antigua Estaciâ”śâ”‚n de Utrillas. La fotâ”śâ”‚grafa, a la izquierda, es Virginia Espa, y el fotâ”śâ”‚grafo que los re-retrata, Mariano Alfonso. Por los huecos de los derrumbados tejados de los Depâ”śâ”‚sitos, hay visual de las ventanas de los bloques de la calle Castelar-Valentâ”śÂˇn Zabala. Lo que de estos arcos no cayâ”śâ”‚ por el paso del tiempo y la dejadez, fue activamente derribado unos aâ”śâ–’os despuâ”śÂ®s. Fuente visual: Imagen amablemente aportada por Oskarskroten Bazofia-Records.', 1985, 1985, 1985, 'Anos 80', 'SAN JOSâ”śĂ«', 41.63922800, -0.86757100, '0101000020E610000011A8FE4124C3EBBF00581D39D2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20274515091.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20274515091.webp', 'https://www.flickr.com/photos/zaragozaantigua/20274515091/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22890, 'Estaciâ”śâ”‚n de Utrillas 1985', 'Vista de la Estaciâ”śâ”‚n de Utrillas desde el seco mar de vâ”śÂˇas, sin balasto, raâ”śÂˇles, travesaâ”śâ–’os, ni unidades. Abandonada desde 1966, era propiedad privada que la mantenâ”śÂˇa en barbecho espectante al albur de las fluctuaciones del mercado inmobiliario. Inmediatamente a la izquierda queda el edificio principal de la Estaciâ”śâ”‚n. A continuaciâ”śâ”‚n, las naves aâ”śâ•‘n en pie de las antiguas cocheras principales de los tranvâ”śÂˇas, a las que se entraba por Miguel Servet, reutilizadas por los autobuses urbanos. En el centro, el mar de vâ”śÂˇas poblado ahora de la vegetaciâ”śâ”‚n esteparia de la zona. A la derecha, restos de edificios e instalaciones auxiliares, como la aguada, la carbonera, el depâ”śâ”‚sito de locomotoras, la chimenea. Al fondo a la derecha, los bloques de viviendas del final de la calle Castelar. Fuente visual: www.flickr.com/photos/ferrocarril-utrillas/9313326358/in/...', 1985, 1985, 1985, 'Anos 80', 'SAN JOSâ”śĂ«', 41.63995000, -0.86791900, '0101000020E6100000FB761211FEC5EBBFA089B0E1E9D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20301579942.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20301579942.webp', 'https://www.flickr.com/photos/zaragozaantigua/20301579942/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22891, 'Estaciâ”śâ”‚n de Utrillas 1989', 'Imagen tomada desde la altura de uno de los bloques de viviendas del Camino de Cabaldâ”śâ”‚s, con panorâ”śĂ­mica visiâ”śâ”‚n del espacio urbano configurado por la Estaciâ”śâ”‚n de Utrillas, algo mâ”śĂ­s de veinte aâ”śâ–’os despuâ”śÂ®s del desmantelamiento de la lâ”śÂˇnea ferroviaria. En primer plano, los edificios e instalaciones de la estaciâ”śâ”‚n: el edificio principal, los andenes, el mar (seco) de vâ”śÂˇas, los muelles, la carbonera, la aguada, la chimenea (en su original ubicaciâ”śâ”‚n), los arcos del depâ”śâ”‚sito de locomotoras... A continuaciâ”śâ”‚n, las enormes cocheras de los tranvâ”śÂˇas, desmantelados doce aâ”śâ–’os antes, ya sin tejados. Luego, los enormes bloques de viviendas que daban a Miguel Servet, el palacio de Larrinaga, los bloques de Castelar... Pasado, presente, y un futuro pendiente. Fuente visual: www.flickr.com/photos/ferrocarril-utrillas/9613999377/in/...', 1989, 1989, 1989, 'Anos 80', 'SAN JOSâ”śĂ«', 41.63995000, -0.86791900, '0101000020E6100000FB761211FEC5EBBFA089B0E1E9D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20335566161.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20335566161.webp', 'https://www.flickr.com/photos/zaragozaantigua/20335566161/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22894, 'Estaciâ”śâ”‚n de Utrillas 1985', 'Imagen capturada desde las alturas del Camino Cabaldâ”śâ”‚s del entorno de la antigua estaciâ”śâ”‚n de Utrillas, destacando la estructura del arqueado depâ”śâ”‚sito de locomotoras. A la derecha, los bloques de viviendas del final de la calle Castelar. Al fondo, los dos bloques gemelos de Miguel Servet-calle Puebla de Hâ”śÂˇjar. En el centro, la mole de Miguel Servet 174-178. A la izquierda, Giesa, y las cocheras de los autobuses urbanos. Fuente visual: www.facebook.com/photo.php?fbid=10202317028127396&set...', 1985, 1985, 1985, 'Anos 80', 'SAN JOSâ”śĂ«', 41.63995000, -0.86791900, '0101000020E6100000FB761211FEC5EBBFA089B0E1E9D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20490273125.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20490273125.webp', 'https://www.flickr.com/photos/zaragozaantigua/20490273125/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22899, 'Centro Deportivo La Granja 1989', 'Centro Deportivo Municipal La Granja en el camino de Cabaldâ”śâ”‚s, sobre terrenos de la antigua Granja Agrâ”śÂˇcola, en una vista aâ”śÂ®rea que en el centro muestra sus diversos equipamientos (campo de fâ”śâ•‘tbol de hierba, pista de atletismo, pabellâ”śâ”‚n cubierto, piscinasĂ”Ă‡ÂŞ). Hacia el fondo, parque de la Granja y viviendas del barrio de san Josâ”śÂ®. En primer tâ”śÂ®rmino, obras de construcciâ”śâ”‚n del nuevo pabellâ”śâ”‚n municipal de deportes, y a la derecha zona donde luego se prolongarâ”śÂˇa la avenida de Cesâ”śĂ­reo Alierta.', 1989, 1989, 1989, 'Anos 80', 'SAN JOSâ”śĂ«', 41.63574600, -0.86809300, '0101000020E6100000705E9CF86AC7EBBF0A48FB1F60D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21002428748.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21002428748.webp', 'https://www.flickr.com/photos/zaragozaantigua/21002428748/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22980, 'Miguel Servet 1992', 'Imagen de la fachada principal del antiguo edificio de Direcciâ”śâ”‚n y Oficinas Generales de la empresa "Tranvâ”śÂˇas de Zaragoza S. A.", edificada en el nâ”¬â•‘ 113-115 de la calle de Miguel Servet, en la manzana entre Yolanda de Bar y Guiral. A su derecha se habilitâ”śâ”‚ un taller para trolebuses y autobuses, y el resto de la manzana fue destinado a cocheras de trolebuses y autobuses. La entrada principal estaba en la parte central del edificio, en la zona delimitada por los pilares. En el friso superior estaba el râ”śâ”‚tulo que lo identificaba "Los Tranvâ”śÂˇas de Zaragoza S. A.". Tras la fulminaciâ”śâ”‚n de los tranvâ”śÂˇas, el edificio quedâ”śâ”‚ sin uso, luego fue piqueteado y sustituido por recientes bloques de viviendas. Fuente: "Zaragoza barrio a barrio"', 1992, 1992, 1992, 'Anos 90', 'SAN JOSâ”śĂ«', 41.63969300, -0.86589200, '0101000020E6100000EBC6BB2363B5EBBF753DD175E1D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15768101778.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15768101778.webp', 'https://www.flickr.com/photos/zaragozaantigua/15768101778/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22986, 'Estaciâ”śâ”‚n de Miraflores 1994', 'Imagen de la Estaciâ”śâ”‚n de Miraflores con el sol a la espalda, de buena maâ”śâ–’ana, y encima de la metâ”śĂ­lica pasarela peatonal sobre cuyos restos arqueolâ”śâ”‚gicos hoy descansa el terraplâ”śÂ®n del Tercer Cinturâ”śâ”‚n de Ronda. Buena idea esa de tomar una foto con el sol de espaldas. Es una de las cosas buenas del sureste de la ciudad: los primeros rayos de Sol de una maâ”śâ–’ana fresca y tranquila invitan a echar un vistazo panorâ”śĂ­mico como este. A la izquierda, la doble vâ”śÂˇa del ferrocarril a Barcelona, el puente del Camino de Cabaldâ”śâ”‚s, y las moles del literal final de Tenor Fleta. En el centro de la imagen, la veterana Estaciâ”śâ”‚n de Miraflores, levemente ensuciada por autoproclamados "escritores". Detrâ”śĂ­s, edificios auxiliares de la Estaciâ”śâ”‚n, incluyendo el de vivienda de operarios, y el reciente de la subestaciâ”śâ”‚n elâ”śÂ®ctrica en sobrio estilo bâ”śâ•‘nker post-nuclear (de hecho, hoy es la â”śâ•‘nica estructura superviviente, al lado del fâ”śÂ®retro de cemento). A la derecha, un viejo ramal de vâ”śÂˇa recuerda la clausurada conexiâ”śâ”‚n con la Estaciâ”śâ”‚n de Utrillas, por donde los lignitos turolenses se encaminaban al Mediterrâ”śĂ­neo. A la derecha y al fondo, entre mecanos y altas tensiones, los veteranos bloques de Josâ”śÂ® Galiay y los mâ”śĂ­s modernos de Pablo Remacha, y el primer bloque de Luis Aula. Mira que se ven cosas sin el Sol cegâ”śĂ­ndote. Fuente visual: AVV "La Granja" barrio de San Josâ”śÂ®.', 1994, 1994, 1994, 'Anos 90', 'SAN JOSâ”śĂ«', 41.63220400, -0.86675000, '0101000020E610000023DBF97E6ABCEBBF4033880FECD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19676569993.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19676569993.webp', 'https://www.flickr.com/photos/zaragozaantigua/19676569993/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24958, 'Parque de Primo de Rivera 1970', 'Imagen capturada en el Parque Primo de Rivera y centrada en una seâ”śâ–’orita observando en proximidad el pâ”śÂ®treo bulto redondo que singularizaba la pequeâ”śâ–’a fuente ornamental denominada de forma no oficial como el "Manneken Pis de Zaragoza" por estar inspirada en la simpâ”śĂ­tica y broncâ”śÂˇnea figurita bruselense que representa un "hombrecito que orina" en cueros vivos. Otros mâ”śĂ­s castizos y llanos lo bautizaron como "La Fuente del Meoncico". Fuese Manneken o fuese Meoncico, los indâ”śÂˇgenas zaragozanos a los que les molestan mucho las inspiraciones inmigrantes o no patrias como esta se encargaron a conciencia en el marco de una canicular noche del verano de ese mismo aâ”śâ–’o, de arrancar al Manneken-Meoncico de su base y hacerlo desaparecer para siempre. Quedaron apenas en el lugar sus piececitos y la parte inferior del soporte por el que ascendâ”śÂˇa el chorrito de agua-"orina". El servicio de Parques y Jardines no enmendâ”śâ”‚ esta destrucciâ”śâ”‚n y fuese y no hubo nada.', 1970, 1970, 1970, 'Anos 70', 'UNIVERSIDAD', 41.63158000, -0.89784500, '0101000020E61000005E11FC6F25BBECBF62670A9DD7D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54673325400.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54673325400.webp', 'https://www.flickr.com/photos/zaragozaantigua/54673325400/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22989, 'Estaciâ”śâ”‚n de Utrillas 1997', 'Desde altura, en el nâ”¬â•‘ 3 de la Plaza de Utrillas, un vistazo al estado del entorno de la antigua Estaciâ”śâ”‚n cuando ya estaba bastante avanzado el proceso de urbanizaciâ”śâ”‚n de los terrenos que la rodeaban. Ya casi terminada, a la izquierda, la gran pastilla de viviendas alabeada por Camino de Cabaldâ”śâ”‚s, Valentâ”śÂˇn Zabala-Castelar, â”śĂĽngel Sanz Briz y Cesâ”śĂ­reo Alierta. Quedaba el enorme terraplâ”śÂ®n interior, en medio, que soportarâ”śÂˇa a duras penas luego a una nueva gran superficie comercial metida con calzador, por decirlo de alguna forma. Poco despuâ”śÂ®s se produjo el traslado de la molesta chimenea estacionaria, que edificaron antiguamente sin pensar en las medidas de los bloques que se habrâ”śÂˇan de construir despuâ”śÂ®s. De no ser porque tenâ”śÂˇa (y mantiene) ocupas de la familia Ciconiidae, esta chimenea hubiera sido trasladada donde el resto de estructuras y edificios de la antigua Estaciâ”śâ”‚n, incluido su irrepetible Depâ”śâ”‚sito de locomotoras ("los Arcos"). Quedaba por darle una nueva vida a los dos edificios supervivientes de la Estaciâ”śâ”‚n, previa recuperaciâ”śâ”‚n-dignificaciâ”śâ”‚n. Sobre si esto asâ”śÂˇ ha sido, hay diferentes opiniones. En que el resultado global es manifiestamente mejorable, hasta las cigâ”śâ•ťeâ”śâ–’as lo ven claro, desde su aireada y despejada atalaya. Fuente visual: Imâ”śĂ­genes Antiguas de Zaragoza.', 1997, 1997, 1997, 'Anos 90', 'SAN JOSâ”śĂ«', 41.64036700, -0.86774800, '0101000020E6100000CA6B257497C4EBBF0438BD8BF7D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20285640332.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20285640332.webp', 'https://www.flickr.com/photos/zaragozaantigua/20285640332/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22990, 'Estaciâ”śâ”‚n de Utrillas 1997', 'Instantâ”śĂ­nea capturada durante el invernal traslado de la chimenea de la antigua compaâ”śâ–’â”śÂˇa Minas y Ferrocarriles de Utrillas, construida en 1925, desde su emplazamiento original en la carbonera de la Estaciâ”śâ”‚n de Utrillas, a 80 m. al SE, para no agobiar a la nueva Gran Superficie Comercial que se iba a construir. Se salvâ”śâ”‚ por una pluma: por ser hogar de cigâ”śâ•ťeâ”śâ–’as. Fuente visual: Foto Pilar Delgado, en AVV. San Josâ”śÂ®.', 1997, 1997, 1997, 'Anos 90', 'SAN JOSâ”śĂ«', 41.63995000, -0.86791900, '0101000020E6100000FB761211FEC5EBBFA089B0E1E9D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20299917216.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20299917216.webp', 'https://www.flickr.com/photos/zaragozaantigua/20299917216/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
